import{_ as e,c as a,o as r,a as n}from"./app.3fdcf20e.js";const k=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[{"level":2,"title":"What kernel version?","slug":"what-kernel-version","link":"#what-kernel-version","children":[]},{"level":2,"title":"Does this replace iptables?","slug":"does-this-replace-iptables","link":"#does-this-replace-iptables","children":[]},{"level":2,"title":"Performance overhead?","slug":"performance-overhead","link":"#performance-overhead","children":[]},{"level":2,"title":"Can SYNPROXY break connections?","slug":"can-synproxy-break-connections","link":"#can-synproxy-break-connections","children":[]},{"level":2,"title":"Hardware offload?","slug":"hardware-offload","link":"#hardware-offload","children":[]},{"level":2,"title":"TUI stuck at Loading?","slug":"tui-stuck-at-loading","link":"#tui-stuck-at-loading","children":[]},{"level":2,"title":"Verifier fails on some kernels?","slug":"verifier-fails-on-some-kernels","link":"#verifier-fails-on-some-kernels","children":[]}],"relativePath":"openshield-xdp/faq/index.md","lastUpdated":1782412920000}'),i={name:"openshield-xdp/faq/index.md"},o=n('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-hidden="true">#</a></h1><h2 id="what-kernel-version" tabindex="-1">What kernel version? <a class="header-anchor" href="#what-kernel-version" aria-hidden="true">#</a></h2><p>Linux \u2265 5.8. \u2265 5.11 for freplace.</p><h2 id="does-this-replace-iptables" tabindex="-1">Does this replace iptables? <a class="header-anchor" href="#does-this-replace-iptables" aria-hidden="true">#</a></h2><p>No. XDP layer (before skb allocation) vs Netfilter (much later). Complementary.</p><h2 id="performance-overhead" tabindex="-1">Performance overhead? <a class="header-anchor" href="#performance-overhead" aria-hidden="true">#</a></h2><p>~300\u2013500 ns normal. ~1\u20132 \u03BCs under attack. ~50\u201370% single-core at 10M PPS.</p><h2 id="can-synproxy-break-connections" tabindex="-1">Can SYNPROXY break connections? <a class="header-anchor" href="#can-synproxy-break-connections" aria-hidden="true">#</a></h2><p>Off by default. When enabled, only intercepts SYN + ACK. Kernel completes real handshake once cookie verified.</p><h2 id="hardware-offload" tabindex="-1">Hardware offload? <a class="header-anchor" href="#hardware-offload" aria-hidden="true">#</a></h2><p><code>xdp_mode: auto</code> tries offload \u2192 native \u2192 generic. Requires smart NIC.</p><h2 id="tui-stuck-at-loading" tabindex="-1">TUI stuck at Loading? <a class="header-anchor" href="#tui-stuck-at-loading" aria-hidden="true">#</a></h2><p><code>sudo openshield fix &amp;&amp; sudo openshield load</code></p><h2 id="verifier-fails-on-some-kernels" tabindex="-1">Verifier fails on some kernels? <a class="header-anchor" href="#verifier-fails-on-some-kernels" aria-hidden="true">#</a></h2><p>Run <code>sudo openshield fix</code>. Stale pins from old versions are the most common cause.</p>',15),s=[o];function l(t,d,c,h,f,p){return r(),a("div",null,s)}const m=e(i,[["render",l]]);export{k as __pageData,m as default};
